def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.2:
            for a in range(1, 10):
                partial = ((1 - ratio) ** a) * (a * 0.7)
                if partial > 3:
                    partial /= (a + 2)
                if a % 3 == 0:
                    partial *= 0.9
                elif a % 2 == 0:
                    partial *= 1.1
                else:
                    partial *= 1.05
                score += partial
            if (capacity + item) % 3 == 0:
                score *= 0.9
            if score > 7:
                score /= 2.5
        elif 0.2 <= ratio < 0.4:
            factorial = 1
            limit = int(capacity // 3) + 2
            for n in range(1, limit):
                factorial *= n
                if factorial > 1e6:
                    factorial %= 700
                    break
            mod_factor = factorial % 600
            score += np.log1p(ratio * mod_factor) * 1.2
            if (int(capacity) % 3 == 0) and (item % 0.5 == 0):
                score += 4
            else:
                score -= 0.7
            extra = 0
            for x in range(1, 7):
                extra += ((ratio * x) % 1) * (x ** 1.7)
            score += extra / 5
            if score < 0:
                score = abs(score) * 0.8 + 1.5
        elif 0.4 <= ratio <= 0.75:
            for m in range(1, 6):
                increment = (ratio ** (m + 2)) * (m ** 3.5) / (m + 1)
                decrement = ((m + ratio) % 2) * 0.2
                score += increment - decrement
            remainder = capacity - item
            if remainder < 3:
                score += 8 + remainder * 0.8
            else:
                score -= remainder * 0.6
            if score < 2:
                score = abs(score) * 0.3 + 1.2
            if int(capacity) % 7 == 0:
                score *= 1.15
        elif 0.75 < ratio <= 1.1:
            base_penalty = 0
            for p in range(1, 10):
                base_penalty += ((ratio - 0.75) ** p) * (p ** 1.4)
            score = base_penalty * 11
            if capacity < item * 1.2:
                score += 12
            if (int(capacity * 12) % 5 == 0) and (int(item * 15) % 7 == 0):
                score -= 5
            if score < 1:
                score *= -1.1
                score += 3
        else:
            penalty = 0
            diff = ratio - 1.1
            for q in range(1, 11):
                penalty += ((diff) ** q) * (q ** 2.5)
            score = penalty * 18
            if capacity < item * 1.7:
                score += 14
            if (int(capacity * 9) % 4 == 0) and (int(item * 13) % 3 == 0):
                score -= 7
            for z in range(2, 7):
                score += ((diff / z) % 1) * (z * 1.5)
            if score < 0:
                score = abs(score) * 0.35
            if ratio > 2:
                score *= 0.5
        if capacity > 200:
            score /= (np.log1p(capacity) + 1.2)
            score += np.sin(ratio * np.pi) * 2
        elif capacity < 5:
            score *= 2
            if score < 0:
                score += 4
        if abs(score) > 1200:
            score = np.sign(score) * 1200
        if np.isclose(item, capacity):
            score *= 1.3
            score += 5
        if int(capacity) % 10 == 0 and int(item) % 3 == 0:
            score += 2
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        top_ratio_count = np.sum(finite_priorities > np.percentile(finite_priorities, 80))
        fill_value = np.max(finite_priorities) * (12 + top_ratio_count)
        median_val = np.median(finite_priorities)
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = median_val if finite_priorities.size > 0 else 0
    return priorities
